-- Limpia las filas de cobertura genérica (sin sucursal puntual): tenían la
-- coordenada del estado, produciendo "0 km" falsos. Al dejarlas sin coordenada,
-- el panel las muestra como "disponible — contactar" en vez de una distancia
-- inventada. Las sucursales reales conservan su coordenada.
UPDATE public.carrier_coverage
SET lat = NULL, lng = NULL
WHERE ciudad_destino ~* 'cobertura|múltiples|multiples|no especificada|sucursales totales|1200\+|65 sucursales|destinos totales|estatal';
